#include <bits/stdc++.h>
using namespace std;
int n,m,i,j,a[2010],f[2010],t[2010];
int main(void){
	cin>>n>>m;
	for(i=1;i<=n;i++)cin>>a[i];
	f[0]=t[0]=1;
	for(i=1;i<=n;i++)
		for(j=m;j>=a[i];j--){
			f[j]=(f[j]+f[j-a[i]])%10;
			t[j]=f[j];
		}
	for(i=1;i<=n;i++){
		for(j=a[i];j<=m;j++)t[j]=(t[j]-t[j-a[i]]+10000)%10;
		for(j=1;j<=m;j++){
			cout<<t[j]%10;
			t[j]=f[j];
		}cout<<'\n';
	}
	return false;
}
